/**
 * gen-types-with-header.js
 * REQ-API-006: supabase gen types 출력에 문서 헤더를 보존한다.
 *
 * 배경: `supabase gen types` CLI 는 파일을 완전히 덮어쓰므로, 헤더 주석이
 * 매번 사라진다. 본 스크립트는 임시 파일에 출력한 뒤 헤더를 prepend 하여
 * src/types/supabase.ts 로 이동한다.
 *
 * 사용: npm run gen-types
 */
const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const HEADER = `/**
 * Supabase Database 타입 (자동 생성)
 * REQ-API-006: 이 파일은 \`npm run gen-types\` 로 생성된다.
 * DO NOT EDIT THIS FILE DIRECTLY — 스키마 변경 후 반드시 gen-types 를 다시 실행한다.
 *
 * 생성 명령: supabase gen types --local --lang typescript --schema public
 */

`;

const outputPath = path.join(process.cwd(), 'src/types/supabase.ts');
const tmpPath = outputPath + '.tmp';

// 1. 임시 파일에 원본 gen-types 출력 작성
execSync(
  'supabase gen types --local --lang typescript --schema public > ' + tmpPath,
  { stdio: 'inherit' },
);

// 2. 헤더 + 원본 출력 결합
const generated = fs.readFileSync(tmpPath, 'utf8');
fs.writeFileSync(outputPath, HEADER + generated);

// 3. 임시 파일 정리
fs.unlinkSync(tmpPath);

// eslint-disable-next-line no-console
console.log('✓ src/types/supabase.ts generated with documentation header');
